
        /* === JUST A CLICKER GAME — BETA V1.20.5.0 === */

        // ── Dev-mode error capture ─────────────────────────────────────────────
        // Collects uncaught errors and unhandled promise rejections into
        // window._devErrors (capped at 50 entries). Inspect in the browser
        // console with: window._devErrors — zero player-facing impact.
        window._devErrors = window._devErrors || [];
        window.addEventListener('error', (e) => {
            window._devErrors.push({ type: 'error', msg: e.message, file: e.filename, line: e.lineno, time: Date.now() });
            if (window._devErrors.length > 50) window._devErrors.shift();
        });
        window.addEventListener('unhandledrejection', (e) => {
            window._devErrors.push({ type: 'promise', msg: String(e.reason), time: Date.now() });
            if (window._devErrors.length > 50) window._devErrors.shift();
        });

        // ── Namespace stub ─────────────────────────────────────────────────────
        // Centralises all exported globals under window.JACG to avoid collisions
        // with browser extensions and future third-party scripts.  Existing code
        // still uses the bare window.* names; JACG is additive, not a replacement.
        window.JACG = window.JACG || {};

        /* --- EXPANDED CONFIGURATION --- */
        // ITEMS, PP_UPGRADES, BCAT, BUILDING_IMG_DATA, SHOP_ICON_IMG_DATA extracted to data.js.
        // data.js must be loaded before game.js in index.html (see script tags at bottom of body).

        // ─── data.js contents (ITEMS, PP_UPGRADES, BCAT, image data) ── see data.js ──

        function getPPBonus() {
            const u = state.ppUpgrades || {};
            let ppPassivePct = 0, ppDemoPct = 0, ppClickBonus = 0, ppCityGridPct = 0, ppCritChance = 0, ppComboTier = 0;
            let ppDoubleGen = false, ppIntelPct = 0, ppUrbanLegend = false, ppGenMult = 1, ppWalkSpeed = 1, ppFragTrickle = 0, ppResonanceGrace = 0;
            PP_UPGRADES.forEach(upg => {
                const lvl = u[upg.id] || 0;
                if (!lvl) return;
                const fx = upg.effect(lvl);
                if (fx.ppPassivePct) ppPassivePct += fx.ppPassivePct;
                if (fx.ppDemoPct)    ppDemoPct    += fx.ppDemoPct;
                if (fx.ppClickBonus) ppClickBonus += fx.ppClickBonus;
                if (fx.ppCityGridPct) ppCityGridPct += fx.ppCityGridPct;
                if (fx.ppDoubleGen)  ppDoubleGen   = true;
                if (fx.ppIntelPct)   ppIntelPct   += fx.ppIntelPct;
                if (fx.ppUrbanLegend) ppUrbanLegend = true;
                if (fx.ppGenMult)    ppGenMult     = Math.max(ppGenMult, fx.ppGenMult);
                if (fx.ppWalkSpeed)  ppWalkSpeed   = Math.max(ppWalkSpeed, fx.ppWalkSpeed);
                if (fx.ppCritChance) ppCritChance += fx.ppCritChance;
                if (fx.ppComboTier)  ppComboTier  = Math.max(ppComboTier, fx.ppComboTier);
                if (fx.ppFragTrickle)    ppFragTrickle    += fx.ppFragTrickle;
                if (fx.ppResonanceGrace) ppResonanceGrace += fx.ppResonanceGrace;
            });
            return { ppPassivePct, ppDemoPct, ppClickBonus, ppCityGridPct, ppDoubleGen, ppIntelPct, ppUrbanLegend, ppGenMult, ppWalkSpeed, ppCritChance, ppComboTier, ppFragTrickle, ppResonanceGrace };
        }

        /* BCAT — see data.js */

        function _recomputeAdjacency() {
            if (!state.city || !Array.isArray(state.city.slots)) {
                state._adjEPS = 0; state._adjPP = 0; return;
            }
            const slots = state.city.slots;
            const COLS = City.COLS || 8;
            const ROWS = City.ROWS || 8;
            let epsB = 0, ppB = 0;
            const seen = new Set();
            const neighbors = idx => {
                const r = Math.floor(idx / COLS), c = idx % COLS, res = [];
                if (r > 0)        res.push(idx - COLS);
                if (r < ROWS - 1) res.push(idx + COLS);
                if (c > 0)        res.push(idx - 1);
                if (c < COLS - 1) res.push(idx + 1);
                return res;
            };
            for (let i = 0; i < slots.length; i++) {
                if (!slots[i]) continue;
                const a = BCAT[slots[i]];
                for (const j of neighbors(i)) {
                    if (!slots[j]) continue;
                    const key = i < j ? `${i}:${j}` : `${j}:${i}`;
                    if (seen.has(key)) continue;
                    seen.add(key);
                    const b = BCAT[slots[j]];
                    if (!a || !b) continue;
                    if ((a==='residential'&&b==='civic')||(a==='civic'&&b==='residential')) ppB  += 0.25;
                    else if (a==='industry' && b==='industry') epsB += 0.18;
                    else if (a==='tech'     && b==='tech')     epsB += 0.28;
                    else if (a==='civic'    && b==='civic')    ppB  += 0.15;
                    else if (a==='nature'   || b==='nature')   ppB  += 0.12;
                }
            }
            state._adjEPS = Math.min(epsB, 4.0);
            state._adjPP  = Math.min(ppB,  3.0);
        }

        function _countDistrict(type) {
            if (!state.city || !Array.isArray(state.city.slots)) return 0;
            return state.city.slots.filter(s => {
                const b = CITY_BUILDINGS.find(x => x.id === s);
                return b && b.district && b.districtType === type;
            }).length;
        }
        // District effect getters — called by passive loop / bird system.
        // Each district type is capped so a full all-one-type grid (64 buildings × bonus)
        // cannot trivialise progression. Caps raised 50% in V1.20.1.9 to restore long-term
        // city strategy incentive — players were hitting old caps too quickly.
        function getDistrictEPSMult()     { return Math.min(6.0, 1 + _countDistrict('industry') * 0.18); }  // cap ×6.0 (~28 bldgs)
        function getDistrictFragMult()    { return Math.min(5.0, 1 + _countDistrict('research') * 0.25); }  // cap ×5.0 (~16 bldgs)
        function getDistrictAnomalyMult() { return Math.min(4.5, 1 + _countDistrict('anomaly')  * 0.20); }  // cap ×4.5 (~18 bldgs)
        function getDistrictLPPerMin()    { return Math.min(24,      _countDistrict('sim')       * 0.4);  }  // cap 24 LP/min (~60 bldgs)

