        /* migrate() — see state.js */

        /* --- STATE SANITIZER ---
           sanitizeState() checks every numeric currency for NaN/Infinity and resets
           to safe defaults. Returns true if any value was corrected so the caller can
           surface a visible warning to the player.
           Called from Game.save() and from the post-prestige reset path.       */
        function sanitizeState() {
            let dirty = false;
            const checks = [
                { path: () => state.energy,        set: v => { state.energy = v; },        def: 0, label: 'energy'       },
                { path: () => state.multiplier,     set: v => { state.multiplier = v; },     def: 1, label: 'multiplier',  min: 1 },
                { path: () => state.fragments,      set: v => { state.fragments = v; },      def: 0, label: 'fragments'    },
                { path: () => state.slag,           set: v => { state.slag = v; },           def: 0, label: 'slag'         },
                { path: () => state.data,           set: v => { state.data = v; },           def: 0, label: 'data'         },
                { path: () => state.instability,    set: v => { state.instability = v; },    def: 0, label: 'instability'  },
                { path: () => state._corruptedData, set: v => { state._corruptedData = v; }, def: 0, label: 'corruptedData'},
            ];
            // prestige.lp checked separately since it's nested
            if (state.prestige && (!isFinite(state.prestige.lp) || isNaN(state.prestige.lp))) {
                console.warn('[NeonNexus] NaN in prestige.lp — resetting to 0');
                state.prestige.lp = 0;
                dirty = true;
            }
            for (const c of checks) {
                const v = c.path();
                const bad = !isFinite(v) || isNaN(v) || (c.min !== undefined && v < c.min);
                if (bad) {
                    console.warn(`[NeonNexus] Bad value in state.${c.label} (${v}) — resetting to ${c.def}`);
                    c.set(c.def);
                    dirty = true;
                }
            }
            return dirty;
        }

        /* --- GENERATOR SYNERGY --- */
        // At 25 owned of any auto generator → +2% global EPS per item hitting the threshold
        // At 50 owned → +5% global EPS (replaces the +2% for that item)
        // Notifications fire once per threshold crossing, stored in state._synergyNotified
        function getSynergyMult() {
            let bonus = 0;
            ITEMS.forEach(i => {
                if (i.type !== 'auto') return;
                const owned = (state.items[i.id] || 0);
                if (owned >= 50)      bonus += 0.05;
                else if (owned >= 25) bonus += 0.02;
            });
            return 1 + bonus;
        }
        function _checkSynergyNotifs() {
            if (!state._synergyNotified) state._synergyNotified = {};
            ITEMS.forEach(i => {
                if (i.type !== 'auto') return;
                const owned = (state.items[i.id] || 0);
                if (owned >= 50 && !state._synergyNotified[i.id + '_50']) {
                    state._synergyNotified[i.id + '_50'] = true;
                    setTimeout(() => showNotif(`⚙ SYNERGY PEAK: ${i.name} ×50 — generator network fully synchronized. +5% global EPS.`, '#66ddcc', 7000), 150);
                } else if (owned >= 25 && !state._synergyNotified[i.id + '_25']) {
                    state._synergyNotified[i.id + '_25'] = true;
                    setTimeout(() => showNotif(`⚙ SYNERGY LINK: ${i.name} ×25 — distributed load detected. +2% global EPS.`, '#44bbaa', 6000), 150);
                }
            });
        }

        /* DEFAULT_STATE — see state.js */

        let state = JSON.parse(JSON.stringify(DEFAULT_STATE));
