                            const t2 = document.getElementById('world-event-ticker');
                            if (t2 && t2.textContent.includes('BROADCAST')) { t2.style.display='none'; t2.onclick=null; t2.style.cursor=''; }
                            setTimeout(_runBroadcast, 240000);
