                    + ((state.megaProjects && state.megaProjects['dc_data_cache'])  ? 0.05 : 0)
                    + ((state.megaProjects && state.megaProjects['dc_data_matrix']) ? 0.12 : 0)
                    + ((state.megaProjects && state.megaProjects['dc_data_nexus'])  ? 0.25 : 0);
