        // ── 3. PAGE VISIBILITY / SENTIENT TAB ──────────────────────────────
        const SentientTab = (() => {
            const AWAY_MSGS = [
                { t: 5,    title: 'Where did you go?' },
                { t: 20,   title: 'The simulation continues without you.' },
                { t: 60,   title: 'It\'s so dark in here.' },
                { t: 120,  title: 'Are you coming back?' },
                { t: 300,  title: 'THEY ARE LOOKING AT ME.' },
            ];
            let _hiddenSince = 0;
            let _msgIdx = 0;
            let _ticker = null;
            let _origTitle = document.title;

            function _init() {
                document.addEventListener('visibilitychange', () => {
                    if (document.hidden) {
                        _hiddenSince = Date.now();
                        _msgIdx = 0;
                        _ticker = setInterval(_escalate, 5000);
                    } else {
                        clearInterval(_ticker);
                        document.title = _origTitle;
                        const gone = (Date.now() - _hiddenSince) / 1000;
                        if (gone > 300) {
                            // Returning after 5+ minutes — WELCOME BACK ABANDONER
                            _showAbandonScreen();
                        }
                    }
                });
            }

            function _escalate() {
                if (!document.hidden) { clearInterval(_ticker); return; }
                const elapsed = (Date.now() - _hiddenSince) / 1000;
                for (let i = AWAY_MSGS.length - 1; i >= 0; i--) {
                    if (elapsed >= AWAY_MSGS[i].t) {
                        document.title = AWAY_MSGS[i].title;
                        break;
                    }
                }
            }

            function _showAbandonScreen() {
                const div = document.createElement('div');
                div.style.cssText = `position:fixed;inset:0;z-index:99999;background:#000;
                    display:flex;align-items:center;justify-content:center;
                    font-family:'Courier New',monospace;font-size:clamp(1.2rem,4vw,2.5rem);
                    color:#fff;letter-spacing:6px;text-transform:uppercase;text-align:center;
                    pointer-events:none;`;
                div.textContent = 'WELCOME BACK, ABANDONER';
                document.body.appendChild(div);
                document.title = _origTitle;
                setTimeout(() => div.remove(), 1200);
            }

            _init();
            return {};
        })();

        // ── 4. COWARDLY BUTTONS ─────────────────────────────────────────────
        const CowardlyButtons = (() => {
            let _active = false;
            let _targets = [];
            const COWARD_LABELS = ['PLEASE DON\'T', 'IT HURTS', 'STOP', 'NOT AGAIN', 'I\'M SCARED'];
            const BUTTON_QUERY = '.shop-item .buy-btn, .nc-buy-btn, #prestige-btn';

            function _activate() {
                if (_active) return;
                _active = true;
                document.addEventListener('mousemove', _onMouseMove, { passive: true });
                // Re-label upgrade buttons
                document.querySelectorAll(BUTTON_QUERY).forEach(btn => {
                    if (!btn.dataset.origLabel) btn.dataset.origLabel = btn.textContent;
                    btn.dataset.cowardLabel = COWARD_LABELS[Math.floor(Math.random() * COWARD_LABELS.length)];
                });
            }

            function _deactivate() {
                if (!_active) return;
                _active = false;
                document.removeEventListener('mousemove', _onMouseMove);
                // Restore labels
                document.querySelectorAll('[data-orig-label]').forEach(btn => {
                    btn.style.transform = '';
                    btn.textContent = btn.dataset.origLabel;
                    delete btn.dataset.origLabel;
                });
            }

            function _onMouseMove(e) {
                if (!_active) return;
                const btns = document.querySelectorAll(BUTTON_QUERY);
                btns.forEach(btn => {
                    const r = btn.getBoundingClientRect();
                    const cx = r.left + r.width / 2, cy = r.top + r.height / 2;
                    const dx = e.clientX - cx, dy = e.clientY - cy;
                    const dist = Math.sqrt(dx * dx + dy * dy);
                    if (dist < 60) {
                        // Flee away from cursor
                        const angle = Math.atan2(dy, dx);
                        const flee = Math.max(0, (60 - dist) / 60) * 18;
                        const fx = -Math.cos(angle) * flee, fy = -Math.sin(angle) * flee;
                        btn.style.transform = `translate(${fx}px, ${fy}px) scale(${0.8 + dist/300})`;
                        if (btn.dataset.cowardLabel) btn.textContent = btn.dataset.cowardLabel;
                        // Quiver
                        btn.style.transition = 'transform 0.06s';
                    } else {
                        btn.style.transform = '';
                        btn.style.transition = 'transform 0.3s';
                        if (btn.dataset.origLabel) btn.textContent = btn.dataset.origLabel;
                    }
                });
            }

            function tick() {
                const instab = state.instability || 0;
                if (instab >= 90 && !_active) _activate();
                else if (instab < 85 && _active) _deactivate();
            }
            return { tick };
        })();
        window.CowardlyButtons = CowardlyButtons;

        // ── 5. TYPOGRAPHICAL ROT (falling digits) ───────────────────────────
        const TypographicalRot = (() => {
            let _lastDrop = 0;
            const DIGITS = '0123456789';

            function _dropDigit() {
                const instab = state.instability || 0;
                if (instab < 70) return;
                const now = Date.now();
                // Rate scales with instability: 70%=rare, 100%=every 3s
                const interval = Math.max(3000, 18000 - instab * 150);
                if (now - _lastDrop < interval) return;
                _lastDrop = now;

                // Pick a random digit from current energy display
                const el = document.getElementById('energy-display');
                if (!el) return;
                const text = el.textContent;
                const digitChars = text.split('').filter(c => DIGITS.includes(c));
                if (!digitChars.length) return;

                const digit = digitChars[Math.floor(Math.random() * digitChars.length)];
                const r = el.getBoundingClientRect();

                const span = document.createElement('div');
                span.className = 'falling-digit';
                span.textContent = digit;
                span.style.left = (r.left + Math.random() * r.width) + 'px';
                span.style.top = r.top + 'px';
                const duration = 2.5 + Math.random() * 1.5;
                span.style.animationDuration = duration + 's';
                span.style.fontSize = (0.8 + Math.random() * 0.6) + 'rem';
                document.body.appendChild(span);
                setTimeout(() => span.remove(), (duration + 0.5) * 1000);
            }

            function tick() { _dropDigit(); }
            return { tick };
        })();
        window.TypographicalRot = TypographicalRot;

